 1вҶ’import AppKit
 2вҶ’
 3вҶ’/// йҖЈзәҢжҚІеӢ•жЁЎејҸдёӯзҡ„е–®дёҖең–зүҮ slot view
 4вҶ’/// дҪҝз”Ё layer-backed GPU жёІжҹ“ (wantsUpdateLayer = true)
 5вҶ’class ImageSlotView: NSView {
 6вҶ’    // MARK: - Properties
 7вҶ’    var imageIndex: Int = -1
 8вҶ’    private var cachedCGImage: CGImage?
 9вҶ’    private var loadTask: Task<Void, Never>?
10вҶ’
11вҶ’    // MARK: - Initialization
12вҶ’    override init(frame frameRect: NSRect) {
13вҶ’        super.init(frame: frameRect)
14вҶ’        wantsLayer = true
15вҶ’        layerContentsRedrawPolicy = .onSetNeedsDisplay
16вҶ’        layer?.contentsGravity = .resize
17вҶ’    }
18вҶ’
19вҶ’    required init?(coder: NSCoder) {
20вҶ’        fatalError("init(coder:) not supported")
21вҶ’    }
22вҶ’
23вҶ’    // MARK: - Layer-backed Rendering
24вҶ’    override var wantsUpdateLayer: Bool { true }
25вҶ’
26вҶ’    override func updateLayer() {
27вҶ’        guard let layer else { return }
