        DebugCentering.log(
            "toggleFullScreen requested wasFullscreen=\(isFullscreen) origin=\(debugPoint(scrollView.contentView.bounds.origin)) " +
            "insets=\(debugInsets(scrollView.contentInsets))"
        )
        view.window?.toggleFullScreen(nil)
