        view.layoutSubtreeIfNeeded()

        // Re-apply AutoFit if in auto-fit mode (not manual zoom)
        if !settings.isManualZoom && settings.alwaysFitOnOpen {
            if let imageSize = currentDocumentSize {
                applyFitting(for: imageSize)
