    @objc func toggleStatusBar(_ sender: Any? = nil) {
        settings.showStatusBar.toggle()
        settings.save()
        applyStatusBar()
        updateWindowTitle()  // еҲҮжҸӣ Status Bar еҫҢжӣҙж–°жЁҷйЎҢеҲ—йЎҜзӨә
    }

    @objc func toggleDualPage(_ sender: Any? = nil) {
